{
  "id": "led_5mm",
  "name": "5mm LED",
  "description": "Standard 5mm through-hole LED. Doubles as an IR transmitter for remote controls (select IR color, drive at 38kHz PWM). Requires a current-limiting resistor. Anode (+) connects to positive supply through resistor, cathode (-) to ground.",
  "ui_placement": true,
  "body": {
    "shape": "circle",
    "height_mm": 8.5,
    "diameter_mm": 5.4
  },
  "mounting": {
    "style": "top",
    "allowed_styles": [
      "top",
      "side"
    ],
    "blocks_routing": false,
    "keepout_margin_mm": 1.0
  },
  "pins": [
    {
      "id": "anode",
      "label": "Anode (+)",
      "position_mm": [
        1.0,
        0
      ],
      "direction": "in",
      "voltage_v": null,
      "current_max_ma": 20,
      "hole_diameter_mm": 0.6,
      "description": "Positive terminal. Connect through current-limiting resistor to V+."
    },
    {
      "id": "cathode",
      "label": "Cathode (-)",
      "position_mm": [
        -1.0,
        0
      ],
      "direction": "in",
      "voltage_v": 0,
      "current_max_ma": 20,
      "hole_diameter_mm": 0.6,
      "description": "Negative terminal. Connect to ground."
    }
  ],
  "internal_nets": [],
  "source_file": "C:\\Users\\S\u00f8ren\\Documents\\GitHub\\manufacturerAI2\\catalog\\led_5mm.json",
  "configurable": {
    "color": {
      "type": "enum",
      "description": "LED color",
      "options": {
        "ir": {
          "wavelength_nm": 940,
          "forward_voltage_v": 1.2
        },
        "red": {
          "wavelength_nm": 620,
          "forward_voltage_v": 2.0
        },
        "orange": {
          "wavelength_nm": 600,
          "forward_voltage_v": 2.1
        },
        "yellow": {
          "wavelength_nm": 590,
          "forward_voltage_v": 2.1
        },
        "green": {
          "wavelength_nm": 525,
          "forward_voltage_v": 2.2
        },
        "blue": {
          "wavelength_nm": 470,
          "forward_voltage_v": 3.2
        },
        "white": {
          "wavelength_nm": 0,
          "forward_voltage_v": 3.3
        },
        "uv": {
          "wavelength_nm": 400,
          "forward_voltage_v": 3.4
        }
      }
    }
  }
}

{
  "id": "resistor_axial",
  "name": "Axial Resistor",
  "description": "Standard through-hole axial resistor. Value is chosen by the agent at design time based on circuit needs (e.g., current limiting for LEDs: R = (Vsupply - Vled) / Iled). Body length varies with power rating but pin spacing is fixed at 8.5mm.",
  "ui_placement": false,
  "body": {
    "shape": "rect",
    "height_mm": 2.4,
    "width_mm": 11,
    "length_mm": 2.4
