  "mounting": {
    "style": "internal",
    "allowed_styles": [
      "internal"
    ],
    "blocks_routing": false,
    "keepout_margin_mm": 1.0
  },
  "pins": [
    {
      "id": "1",
      "label": "Lead 1",
      "position_mm": [
        -4.25,
