    {
      "id": "2",
      "label": "Lead 2",
      "position_mm": [
        4.25,
        0
      ],
      "direction": "bidirectional",
      "voltage_v": null,
      "current_max_ma": 250,
      "hole_diameter_mm": 0.6,
      "description": "Non-polarized. Either lead can be input or output."
    }
  ],
  "internal_nets": [],
